mapper.select:
select s.id, s.name, s.no, s.gender, s.phone, s.degree, # case (degree) # when 1 then '初中' # when 2 then '高中' # when 3 then '大专' # when 4 then '本科' # when 5 then '硕士' # when 6 then '博士' # else '其他' end degree, s.id_card, s.is_college, # if(s.is_college = 1, '是', '否') is_college, s.address, s.graduation_date,s.violation_count,s.violation_score, s.clazz_id, c.name as clazz_name, s.create_time, s.update_time from student s left join clazz c on s.clazz_id = c.id
and s.name LIKE CONCAT('%', #{name}, '%')
and s.degree = #{degree}
and s.clazz_id = #{clazzId}
ORDER BY s.create_time DESC

